// fork() + execvp the third-party binary; keep the read ends of its stdout/
// stderr pipes (non-blocking) so do_loop() can pump them into our logger.
void Phc2sysProvider::do_start() {
    int out_pipe[2] = {-1, -1};
    int err_pipe[2] = {-1, -1};
    if (::pipe(out_pipe) != 0 || ::pipe(err_pipe) != 0) {
        log().error(std::string("[phc2sys] pipe() failed: ") + std::strerror(errno));
        return;
    }

    pid_t pid = ::fork();
    if (pid < 0) {
        log().error(std::string("[phc2sys] fork() failed: ") + std::strerror(errno));
        ::close(out_pipe[0]); ::close(out_pipe[1]);
        ::close(err_pipe[0]); ::close(err_pipe[1]);
        return;
    }
    if (pid == 0) {
        // Child: wire stdout/stderr to the pipe write ends, close the rest,
        // then exec. argv is static + already NUL-terminated.
        ::dup2(out_pipe[1], STDOUT_FILENO);
        ::dup2(err_pipe[1], STDERR_FILENO);
        ::close(out_pipe[0]); ::close(out_pipe[1]);
        ::close(err_pipe[0]); ::close(err_pipe[1]);
        ::execvp(kArgv[0], const_cast<char* const*>(kArgv));
        // exec failed — report on the (redirected) stderr and die. The parent
        // sees EOF + a non-zero wait status and the supervisor restarts us.
        std::fprintf(stderr, "execvp(%s): %s\n", kArgv[0], std::strerror(errno));
        _exit(127);
    }

    // Parent: keep the read ends (non-blocking), drop the write ends.
    ::close(out_pipe[1]);
    ::close(err_pipe[1]);
    ::fcntl(out_pipe[0], F_SETFL, O_NONBLOCK);
    ::fcntl(err_pipe[0], F_SETFL, O_NONBLOCK);
    child_pid_ = pid;
    out_fd_    = out_pipe[0];
    err_fd_    = err_pipe[0];
    log().info(std::string("[phc2sys] forked /usr/sbin/phc2sys pid=") + std::to_string(pid));
}

// Pump the child's stdout (→ info) + stderr (→ warn) into our logger until the
// child exits, then return so the supervisor's restart strategy re-forks us.
void Phc2sysProvider::do_loop() {
    if (child_pid_ < 0) {
        // do_start() failed to fork — back off a beat so a restart storm of
        // this runnable doesn't busy-spin the supervisor.
        for (int i = 0; i < 10 && !stop_requested(); ++i) ::usleep(100 * 1000);
        return;
    }
    std::string out_carry, err_carry;
    bool out_open = true, err_open = true;

    while (!stop_requested() && (out_open || err_open)) {
        struct pollfd fds[2];
        nfds_t nf = 0;
        if (out_open) fds[nf++] = {out_fd_, POLLIN, 0};
        if (err_open) fds[nf++] = {err_fd_, POLLIN, 0};
        int rv = ::poll(fds, nf, 500 /*ms*/);
        if (rv < 0) { if (errno == EINTR) continue; break; }

        for (nfds_t i = 0; i < nf; ++i) {
            if (!(fds[i].revents & (POLLIN | POLLHUP | POLLERR))) continue;
            if (fds[i].fd == out_fd_ && out_open) {
                out_open = drain_fd(out_fd_, out_carry,
                    [this](const std::string& l){ log().info("[phc2sys] " + l); });
            } else if (fds[i].fd == err_fd_ && err_open) {
                err_open = drain_fd(err_fd_, err_carry,
                    [this](const std::string& l){ log().warn("[phc2sys] " + l); });
            }
        }

        // Has the child gone? WNOHANG: don't block the pump.
        int status = 0;
        pid_t w = ::waitpid(child_pid_, &status, WNOHANG);
        if (w == child_pid_) {
            if (!out_carry.empty()) log().info("[phc2sys] " + out_carry);
            if (!err_carry.empty()) log().warn("[phc2sys] " + err_carry);
            std::string how = WIFSIGNALED(status)
                ? ("signal " + std::to_string(WTERMSIG(status)))
                : ("exit " + std::to_string(WEXITSTATUS(status)));
            log().warn(std::string("[phc2sys] /usr/sbin/phc2sys terminated (") + how + ")");
            child_pid_ = -1;
            break;   // return → GenRunnable thread ends → supervisor restarts us
        }
    }
}

// Bring the child down: SIGTERM, brief grace, SIGKILL if it lingers; reap.
void Phc2sysProvider::do_stop() {
    if (child_pid_ > 0) {
        ::kill(child_pid_, SIGTERM);
        for (int i = 0; i < 50; ++i) {   // up to ~5s grace
            if (::waitpid(child_pid_, nullptr, WNOHANG) == child_pid_) { child_pid_ = -1; break; }
            ::usleep(100 * 1000);
        }
        if (child_pid_ > 0) {
            ::kill(child_pid_, SIGKILL);
            ::waitpid(child_pid_, nullptr, 0);
            child_pid_ = -1;
        }
    }
    if (out_fd_ >= 0) { ::close(out_fd_); out_fd_ = -1; }
    if (err_fd_ >= 0) { ::close(err_fd_); err_fd_ = -1; }
}

